import type * as Worker from "../../worker";

type App = typeof Worker.default;

export const link = linkFor<App>();

import { link } from "../shared/links.js";
import { seedUsers } from "../shared/seed.js";

export const Home = () => {
  return (
    <div style={{ fontFamily: "system-ui, sans-serif", padding: "20px" }}>
      <h1>Home Page</h1>
      <p>Welcome to our RedwoodSDK app! Here are our users:</p>
      <ul>
        {seedUsers.map((user) => (
          <li key={user.id}>
            <a href={link("/users/:id", { id: user.id })}>{user.name}</a>
          </li>
        ))}
      </ul>
      <p>
        View the <a href={link("/users")}>Flat Users List</a>
      </p>
    </div>
  );
};

import { link } from "../shared/links.js";
import { seedUsers } from "../shared/seed.js";

export const Users = () => {
  return (
    <div style={{ fontFamily: "system-ui, sans-serif", padding: "20px" }}>
      <h1>Users Flat List</h1>
      <ul>
        {seedUsers.map((user) => (
          <li key={user.id}>
            <a href={link("/users/:id", { id: user.id })}>{user.name}</a>
          </li>
        ))}
      </ul>
      <p>
        <a href={link("/")}>Back to Home</a>
      </p>
    </div>
  );
};

import { link } from "../shared/links.js";
import { seedUsers } from "../shared/seed.js";

export const UserDetail = ({ id }: { id: string }) => {
  const user = seedUsers.find((u) => u.id === id);

  if (!user) {
    return (
      <div style={{ fontFamily: "system-ui, sans-serif", padding: "20px" }}>
        <h1>User Not Found</h1>
        <p>Could not find a user with ID: {id}</p>
        <p>
          <a href={link("/")}>Go Home</a>
        </p>
      </div>
    );
  }

  return (
    <div style={{ fontFamily: "system-ui, sans-serif", padding: "20px" }}>
      <h1>User: {user.name}</h1>
      <p>ID: {user.id}</p>
      <h2>Posts:</h2>
      <ul>
        {user.posts.map((post) => (
          <li key={post.id}>
            <a href={link("/users/:id/posts/:postId", { id: user.id, postId: post.id })}>
              {post.title}
            </a>
          </li>
        ))}
      </ul>
      <p>
        <a href={link("/users")}>Back to Users List</a> | <a href={link("/")}>Go Home</a>
      </p>
    </div>
  );
};

import { link } from "../shared/links.js";
import { seedUsers } from "../shared/seed.js";

export const PostDetail = ({ id, postId }: { id: string; postId: string }) => {
  const user = seedUsers.find((u) => u.id === id);
  const post = user?.posts.find((p) => p.id === postId);

  if (!user || !post) {
    return (
      <div style={{ fontFamily: "system-ui, sans-serif", padding: "20px" }}>
        <h1>Post Not Found</h1>
        <p>Could not find user ID: {id} or post ID: {postId}</p>
        <p>
          <a href={link("/")}>Go Home</a>
        </p>
      </div>
    );
  }

  return (
    <div style={{ fontFamily: "system-ui, sans-serif", padding: "20px" }}>
      <h1>Post Title: {post.title}</h1>
      <p>User ID: <span id="userId">{id}</span></p>
      <p>Post ID: <span id="postId">{postId}</span></p>
      <p>
        <a href={link("/users/:id", { id: user.id })}>Back to User Profile</a>
      </p>
    </div>
  );
};

